import React from 'react';

const CFG = {
  safe:        { label: 'SAFE',     cls: 'badge-safe'     },
  medium:      { label: 'MEDIUM',   cls: 'badge-medium'   },
  high:        { label: 'HIGH',     cls: 'badge-high'     },
  critical:    { label: 'CRITICAL', cls: 'badge-critical' },
  unknown:     { label: 'UNKNOWN',  cls: 'badge-unknown'  },
  whitelisted: { label: 'SAFE',     cls: 'badge-safe'     },
  blocked:     { label: 'BLOCKED',  cls: 'badge-critical' },
};

export default function RiskBadge({ level, pulse = false }) {
  const cfg = CFG[level?.toLowerCase()] || CFG.unknown;
  return (
    <span className={`badge ${cfg.cls}`} style={pulse && level !== 'safe' ? { animation: 'pulse-glow 1.5s infinite' } : {}}>
      <span style={{ width: '5px', height: '5px', borderRadius: '50%', background: 'currentColor', display: 'inline-block' }} />
      {cfg.label}
    </span>
  );
}
